-- ==============================================================
-- VLSI Digital System: Comprehensive VHDL Implementation
-- Covers: Full Adder, 4-bit Ripple Carry Adder, D Flip-Flop,
--         4-bit Synchronous Counter, and 4-bit Comparator
-- Technology: Synthesizable RTL VHDL (IEEE 1076-2008)
-- ==============================================================

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

-- -------------------------------------------------------
-- Component 1: Half Adder
-- -------------------------------------------------------
entity half_adder is
    port (
        A    : in  std_logic;   -- Input bit A
        B    : in  std_logic;   -- Input bit B
        Sum  : out std_logic;   -- Sum output (A XOR B)
        Cout : out std_logic    -- Carry output (A AND B)
    );
end entity half_adder;

architecture rtl of half_adder is
begin
    Sum  <= A xor B;   -- XOR for sum
    Cout <= A and B;   -- AND for carry
end architecture rtl;

-- -------------------------------------------------------
-- Component 2: Full Adder
-- -------------------------------------------------------
entity full_adder is
    port (
        A    : in  std_logic;   -- Input bit A
        B    : in  std_logic;   -- Input bit B
        Cin  : in  std_logic;   -- Carry-in
        Sum  : out std_logic;   -- Sum output
        Cout : out std_logic    -- Carry-out
    );
end entity full_adder;

architecture rtl of full_adder is
    signal s1, c1, c2 : std_logic;  -- Internal signals
begin
    s1   <= A xor B;            -- Partial sum of A and B
    Sum  <= s1 xor Cin;         -- Final sum including carry-in
    c1   <= A and B;            -- Carry from A,B
    c2   <= s1 and Cin;         -- Carry from partial sum and Cin
    Cout <= c1 or c2;           -- Final carry out
end architecture rtl;

-- -------------------------------------------------------
-- Component 3: 4-bit Ripple Carry Adder
-- Uses structural instantiation of full_adder
-- -------------------------------------------------------
entity rca_4bit is
    port (
        A    : in  std_logic_vector(3 downto 0);  -- 4-bit operand A
        B    : in  std_logic_vector(3 downto 0);  -- 4-bit operand B
        Cin  : in  std_logic;                      -- Carry input
        Sum  : out std_logic_vector(3 downto 0);  -- 4-bit Sum
        Cout : out std_logic                       -- Carry out
    );
end entity rca_4bit;

architecture structural of rca_4bit is
    signal carry : std_logic_vector(3 downto 0);  -- Internal carry chain

    component full_adder
        port (
            A    : in  std_logic;
            B    : in  std_logic;
            Cin  : in  std_logic;
            Sum  : out std_logic;
            Cout : out std_logic
        );
    end component;
begin
    -- Instantiate 4 full adders in ripple carry chain
    FA0: full_adder port map (A=>A(0), B=>B(0), Cin=>Cin,      Sum=>Sum(0), Cout=>carry(0));
    FA1: full_adder port map (A=>A(1), B=>B(1), Cin=>carry(0), Sum=>Sum(1), Cout=>carry(1));
    FA2: full_adder port map (A=>A(2), B=>B(2), Cin=>carry(1), Sum=>Sum(2), Cout=>carry(2));
    FA3: full_adder port map (A=>A(3), B=>B(3), Cin=>carry(2), Sum=>Sum(3), Cout=>Cout);
end architecture structural;

-- -------------------------------------------------------
-- Component 4: D Flip-Flop with Synchronous Reset
-- -------------------------------------------------------
entity d_flipflop is
    port (
        clk   : in  std_logic;   -- Clock input (rising edge)
        rst   : in  std_logic;   -- Synchronous active-high reset
        D     : in  std_logic;   -- Data input
        Q     : out std_logic;   -- Q output
        Qbar  : out std_logic    -- Complement output
    );
end entity d_flipflop;

architecture rtl of d_flipflop is
    signal Q_internal : std_logic := '0';  -- Internal state
begin
    process(clk)
    begin
        if rising_edge(clk) then      -- Triggered on rising clock edge
            if rst = '1' then          -- Synchronous reset
                Q_internal <= '0';     -- Reset state to 0
            else
                Q_internal <= D;       -- Sample data input
            end if;
        end if;
    end process;

    Q    <= Q_internal;                -- Drive Q output
    Qbar <= not Q_internal;            -- Drive complement output
end architecture rtl;

-- -------------------------------------------------------
-- Component 5: 4-bit Synchronous Up Counter with Load
-- -------------------------------------------------------
entity counter_4bit is
    port (
        clk   : in  std_logic;                    -- Clock
        rst   : in  std_logic;                    -- Synchronous reset
        en    : in  std_logic;                    -- Count enable
        load  : in  std_logic;                    -- Parallel load enable
        din   : in  std_logic_vector(3 downto 0); -- Load data
        count : out std_logic_vector(3 downto 0); -- Counter output
        tc    : out std_logic                      -- Terminal count (overflow)
    );
end entity counter_4bit;

architecture rtl of counter_4bit is
    signal cnt_reg : unsigned(3 downto 0) := (others => '0');
begin
    process(clk)
    begin
        if rising_edge(clk) then
            if rst = '1' then
                cnt_reg <= (others => '0');    -- Reset to 0000
            elsif load = '1' then
                cnt_reg <= unsigned(din);      -- Parallel load
            elsif en = '1' then
                cnt_reg <= cnt_reg + 1;        -- Increment counter
            end if;
        end if;
    end process;

    count <= std_logic_vector(cnt_reg);        -- Output current count
    tc    <= '1' when cnt_reg = "1111" else '0'; -- Terminal count at 15
end architecture rtl;

-- -------------------------------------------------------
-- Component 6: 4-bit Magnitude Comparator
-- -------------------------------------------------------
entity comparator_4bit is
    port (
        A     : in  std_logic_vector(3 downto 0);  -- 4-bit input A
        B     : in  std_logic_vector(3 downto 0);  -- 4-bit input B
        A_gt_B: out std_logic;   -- A > B
        A_eq_B: out std_logic;   -- A = B
        A_lt_B: out std_logic    -- A < B
    );
end entity comparator_4bit;

architecture rtl of comparator_4bit is
begin
    A_gt_B <= '1' when unsigned(A) > unsigned(B) else '0';
    A_eq_B <= '1' when unsigned(A) = unsigned(B) else '0';
    A_lt_B <= '1' when unsigned(A) < unsigned(B) else '0';
end architecture rtl;

-- -------------------------------------------------------
-- Top-Level: Moore FSM - Sequence Detector (101 pattern)
-- -------------------------------------------------------
entity seq_detector_101 is
    port (
        clk    : in  std_logic;   -- Clock
        rst    : in  std_logic;   -- Active-high reset
        x      : in  std_logic;   -- Serial input
        detect : out std_logic    -- Output: 1 when 101 detected
    );
end entity seq_detector_101;

architecture rtl of seq_detector_101 is
    -- State encoding
    type state_type is (S0, S1, S2, S3);  -- S0=idle, S1=got1, S2=got10, S3=got101
    signal state, next_state : state_type;
begin
    -- State register (sequential)
    process(clk)
    begin
        if rising_edge(clk) then
            if rst = '1' then
                state <= S0;         -- Reset to initial state
            else
                state <= next_state; -- State transition
            end if;
        end if;
    end process;

    -- Next-state and output logic (combinational)
    process(state, x)
    begin
        detect     <= '0';      -- Default output
        next_state <= S0;       -- Default next state

        case state is
            when S0 =>          -- Initial state
                if x = '1' then next_state <= S1;
                else             next_state <= S0;
                end if;
            when S1 =>          -- Received '1'
                if x = '0' then next_state <= S2;
                else             next_state <= S1;
                end if;
            when S2 =>          -- Received '10'
                if x = '1' then next_state <= S3;
                else             next_state <= S0;
                end if;
            when S3 =>          -- Received '101' - DETECT!
                detect <= '1';  -- Output detection
                if x = '1' then next_state <= S1;  -- Overlapping
                else             next_state <= S0;
                end if;
        end case;
    end process;
end architecture rtl;

hdl_code.verilog:
// ==============================================================
// VLSI Digital System: Comprehensive Verilog Implementation
// Covers: Half Adder, Full Adder, 4-bit Adder, D Flip-Flop,
//         4-bit Counter, Comparator, and FSM (101 Detector)
// Standard: IEEE 1364-2001 / SystemVerilog IEEE 1800-2012
// ==============================================================

// -------------------------------------------------------
// Module 1: Half Adder
// -------------------------------------------------------
module half_adder (
    input  wire A,       // Input A
    input  wire B,       // Input B
    output wire Sum,     // A XOR B
    output wire Cout     // A AND B (Carry)
);
    assign Sum  = A ^ B;   // XOR operation
    assign Cout = A & B;   // AND operation (carry)
endmodule

// -------------------------------------------------------
// Module 2: Full Adder
// -------------------------------------------------------
module full_adder (
    input  wire A,       // Input A
    input  wire B,       // Input B
    input  wire Cin,     // Carry-in
    output wire Sum,     // Sum output
    output wire Cout     // Carry-out
);
    wire s1, c1, c2;     // Internal nodes

    assign s1   = A ^ B;          // Partial XOR
    assign Sum  = s1 ^ Cin;       // Final sum
    assign c1   = A & B;          // Carry from A,B
    assign c2   = s1 & Cin;       // Carry from partial
    assign Cout = c1 | c2;        // Output carry
endmodule

// -------------------------------------------------------
// Module 3: 4-bit Ripple Carry Adder (Structural)
// -------------------------------------------------------
module rca_4bit (
    input  wire [3:0] A,     // 4-bit operand A
    input  wire [3:0] B,     // 4-bit operand B
    input  wire       Cin,   // Carry input
    output wire [3:0] Sum,   // 4-bit sum
    output wire       Cout   // Carry out
);
    wire [3:0] carry;        // Internal carry chain

    // Structural instantiation of 4 full adders
    full_adder FA0 (.A(A[0]), .B(B[0]), .Cin(Cin),      .Sum(Sum[0]), .Cout(carry[0]));
    full_adder FA1 (.A(A[1]), .B(B[1]), .Cin(carry[0]), .Sum(Sum[1]), .Cout(carry[1]));
    full_adder FA2 (.A(A[2]), .B(B[2]), .Cin(carry[1]), .Sum(Sum[2]), .Cout(carry[2]));
    full_adder FA3 (.A(A[3]), .B(B[3]), .Cin(carry[2]), .Sum(Sum[3]), .Cout(Cout));
endmodule

// -------------------------------------------------------
// Module 4: D Flip-Flop with Synchronous Reset
// -------------------------------------------------------
module d_flipflop (
    input  wire clk,     // Clock (rising edge triggered)
    input  wire rst,     // Synchronous active-high reset
    input  wire D,       // Data input
    output reg  Q,       // Q output
    output wire Qbar     // Complement output
);
    always @(posedge clk) begin
        if (rst)          // Synchronous reset
            Q <= 1'b0;    // Clear output
        else
            Q <= D;       // Sample data on rising edge
    end

    assign Qbar = ~Q;     // Complement output
endmodule

// -------------------------------------------------------
// Module 5: JK Flip-Flop
// -------------------------------------------------------
module jk_flipflop (
    input  wire clk,     // Clock
    input  wire rst,     // Synchronous reset
    input  wire J,       // J input
    input  wire K,       // K input
    output reg  Q        // Q output
);
    always @(posedge clk) begin
        if (rst)
            Q <= 1'b0;
        else
            case ({J, K})
                2'b00: Q <= Q;    // Hold state
                2'b01: Q <= 1'b0; // Reset
                2'b10: Q <= 1'b1; // Set
                2'b11: Q <= ~Q;   // Toggle
            endcase
    end
endmodule

// -------------------------------------------------------
// Module 6: 4-bit Synchronous Up Counter with Load
// -------------------------------------------------------
module counter_4bit (
    input  wire       clk,    // Clock
    input  wire       rst,    // Synchronous reset
    input  wire       en,     // Count enable
    input  wire       load,   // Parallel load
    input  wire [3:0] din,    // Load data
    output reg  [3:0] count,  // Counter value
    output wire       tc      // Terminal count
);
    always @(posedge clk) begin
        if (rst)
            count <= 4'b0000;    // Reset counter
        else if (load)
            count <= din;        // Load parallel data
        else if (en)
            count <= count + 1;  // Increment
    end

    assign tc = (count == 4'b1111) ? 1'b1 : 1'b0; // Terminal count at 15
endmodule

// -------------------------------------------------------
// Module 7: 4-bit Magnitude Comparator
// -------------------------------------------------------
module comparator_4bit (
    input  wire [3:0] A,       // Input A
    input  wire [3:0] B,       // Input B
    output wire       A_gt_B,  // A > B
    output wire       A_eq_B,  // A = B
    output wire       A_lt_B   // A < B
);
    assign A_gt_B = (A > B) ? 1'b1 : 1'b0;
    assign A_eq_B = (A == B) ? 1'b1 : 1'b0;
    assign A_lt_B = (A < B) ? 1'b1 : 1'b0;
endmodule

// -------------------------------------------------------
// Module 8: 4-to-1 Multiplexer
// -------------------------------------------------------
module mux_4to1 (
    input  wire [3:0] D,    // 4 data inputs
    input  wire [1:0] sel,  // 2-bit select
    output reg        Y     // Output
);
    always @(*) begin
        case (sel)
            2'b00: Y = D[0];
            2'b01: Y = D[1];
            2'b10: Y = D[2];
            2'b11: Y = D[3];
        endcase
    end
endmodule

// -------------------------------------------------------
// Module 9: 3-to-8 Decoder
// -------------------------------------------------------
module decoder_3to8 (
    input  wire [2:0] A,    // 3-bit binary input
    input  wire       en,   // Enable
    output reg  [7:0] Y     // 8-bit one-hot output
);
    always @(*) begin
        if (!en)
            Y = 8'b0000_0000;   // Disabled: all outputs low
        else
            Y = 8'b0000_0001 << A;  // One-hot decode
    end
endmodule

// -------------------------------------------------------
// Module 10: Moore FSM - 101 Sequence Detector
// -------------------------------------------------------
module seq_detector_101 (
    input  wire clk,       // Clock
    input  wire rst,       // Synchronous reset
    input  wire x,         // Serial input
    output reg  detect     // Detection output
);
    // State encoding using parameters
    parameter S0 = 2'b00;  // Idle state
    parameter S1 = 2'b01;  // Received '1'
    parameter S2 = 2'b10;  // Received '10'
    parameter S3 = 2'b11;  // Received '101'

    reg [1:0] state, next_state;  // State registers

    // Sequential: State register update
    always @(posedge clk) begin
        if (rst)
            state <= S0;          // Reset to initial state
        else
            state <= next_state;  // Next state transition
    end

    // Combinational: Next state logic
    always @(*) begin
        next_state = S0;  // Default
        case (state)
            S0: next_state = x ? S1 : S0;
            S1: next_state = x ? S1 : S2;
            S2: next_state = x ? S3 : S0;
            S3: next_state = x ? S1 : S0; // Overlapping detection
        endcase
    end

    // Combinational: Output logic (Moore: based on state only)
    always @(*) begin
        detect = (state == S3) ? 1'b1 : 1'b0;
    end
endmodule

// -------------------------------------------------------
// Module 11: 4-bit Barrel Shifter
// -------------------------------------------------------
module barrel_shifter_4bit (
    input  wire [3:0] D,       // 4-bit data input
    input  wire [1:0] shamt,   // Shift amount (0-3)
    input  wire       dir,     // Direction: 0=left, 1=right
    output reg  [3:0] Y        // Shifted output
);
    always @(*) begin
        if (dir == 1'b0)
            Y = D << shamt;    // Logical left shift
        else
            Y = D >> shamt;    // Logical right shift
    end
endmodule

// -------------------------------------------------------
// Module 12: 4-bit ALU
// -------------------------------------------------------
module alu_4bit (
    input  wire [3:0]  A,       // Operand A
    input  wire [3:0]  B,       // Operand B
    input  wire [2:0]  opcode,  // Operation select
    output reg  [3:0]  result,  // ALU result
    output reg         zero,    // Zero flag
    output reg         carry    // Carry flag
);
    reg [4:0] temp;  // 5-bit for carry detection

    always @(*) begin
        temp   = 5'b0;
        carry  = 1'b0;
        case (opcode)
            3'b000: begin temp = A + B;    carry = temp[4]; end  // ADD
            3'b001: begin temp = A - B;    carry = temp[4]; end  // SUB
            3'b010: temp[3:0] = A & B;                           // AND
            3'b011: temp[3:0] = A | B;                           // OR
            3'b100: temp[3:0] = A ^ B;                           // XOR
            3'b101: temp[3:0] = ~A;                              // NOT A
            3'b110: temp[3:0] = A << 1;                          // Shift Left
            3'b111: temp[3:0] = A >> 1;                          // Shift Right
        endcase
        result = temp[3:0];
        zero   = (result == 4'b0000) ? 1'b1 : 1'b0;
    end
endmodule

