// BCD Counter (Modulo-10)
module bcd_counter (
    input  wire       clk,
    input  wire       rst,    // Global synchronous reset
    output reg  [3:0] count,  // BCD output (0-9)
    output wire       carry   // Carry out at count=9
);
    always @(posedge clk) begin
        if (rst)
            count <= 4'd0;
        else if (count == 4'd9)
            count <= 4'd0;    // Reset after 9 (modulo-10)
        else
            count <= count + 1'b1;
    end

    assign carry = (count == 4'd9) ? 1'b1 : 1'b0;
endmodule

// Cascade two for 0-99 (2-digit BCD)
module bcd_2digit (
    input  wire       clk, rst,
    output wire [3:0] units, tens
);
    wire carry_units;
    bcd_counter U0 (.clk(clk), .rst(rst), .count(units), .carry(carry_units));
    bcd_counter U1 (.clk(clk), .rst(rst || carry_units), .count(tens), .carry());
endmodule

// 8-to-3 Priority Encoder
module priority_encoder_8to3 (
    input  wire [7:0] I,      // 8 input lines (I[7]=highest priority)
    output reg  [2:0] Y,      // 3-bit binary output code
    output reg        valid   // 1 when at least one input is active
);
    always @(*) begin
        valid = 1'b1;  // Assume valid
        casex (I)
            8'b1xxxxxxx: Y = 3'd7;   // I7 highest priority
            8'b01xxxxxx: Y = 3'd6;
            8'b001xxxxx: Y = 3'd5;
            8'b0001xxxx: Y = 3'd4;
            8'b00001xxx: Y = 3'd3;
            8'b000001xx: Y = 3'd2;
            8'b0000001x: Y = 3'd1;
            8'b00000001: Y = 3'd0;   // I0 lowest priority
            default: begin
                Y = 3'd0;
                valid = 1'b0;         // No input active
            end
        endcase
    end
endmodule

// Testbench
module tb_priority_encoder;
    reg  [7:0] I;
    wire [2:0] Y;
    wire       valid;

    priority_encoder_8to3 dut (.I(I), .Y(Y), .valid(valid));

    initial begin
        I = 8'b00001000; #10; // I3 active → Y should be 3
        $display("I=%b Y=%d valid=%b", I, Y, valid);
        I = 8'b10000001; #10; // I7 and I0 → Y should be 7 (priority)
        $display("I=%b Y=%d valid=%b", I, Y, valid);
        I = 8'b00000000; #10; // No input
        $display("I=%b Y=%d valid=%b", I, Y, valid);
        $finish;
    end
endmodule

// 4-bit Barrel Shifter: Left/Right, logical shift
module barrel_shifter (
    input  wire [3:0] D,       // 4-bit data input
    input  wire [1:0] shamt,   // Shift amount: 00=0, 01=1, 10=2, 11=3
    input  wire       dir,     // 0=left, 1=right
    output reg  [3:0] Y        // Shifted output
);
    // MUX-based implementation: 2 stages for 4-bit
    reg [3:0] stage1;  // After first shift stage

    always @(*) begin
        // Stage 1: Shift by shamt[0] (0 or 1)
        if (dir == 1'b0) begin  // Left shift
            stage1 = shamt[0] ? {D[2:0], 1'b0}   : D;
        end else begin          // Right shift
            stage1 = shamt[0] ? {1'b0, D[3:1]}   : D;
        end

        // Stage 2: Shift by shamt[1]*2 (0 or 2)
        if (dir == 1'b0) begin  // Left shift
            Y = shamt[1] ? {stage1[1:0], 2'b00} : stage1;
        end else begin          // Right shift
            Y = shamt[1] ? {2'b00, stage1[3:2]} : stage1;
        end
    end
endmodule

// Compact behavioral version
module barrel_shifter_beh (
    input  wire [3:0] D,
    input  wire [1:0] shamt,
    input  wire       dir,
    output wire [3:0] Y
);
    assign Y = dir ? (D >> shamt) : (D << shamt);
endmodule
